"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["521173"],{860525(e){e.exports=JSON.parse('{"tag":{"label":"prefab","permalink":"/dst-api-webdocs/docs/tags/prefab","allTagsPath":"/dst-api-webdocs/docs/tags","count":81,"items":[{"id":"game-scripts/prefabs/abigail","title":"Abigail","description":"Defines the Abigail prefab and related entities including retaliation attack, vex debuffs, and murder buff prefabs, with complete initialization logic, event handlers, and ghost command functions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/abigail"},{"id":"game-scripts/prefabs/bearger","title":"Bearger","description":"Defines the Bearger and Mutated Bearger boss prefabs, configuring their components, AI, and combat behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bearger"},{"id":"game-scripts/prefabs/bearger_fur","title":"Bearger Fur","description":"Defines the Bearger Fur inventory item prefab, including stacking and hauntable behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bearger_fur"},{"id":"game-scripts/prefabs/bearger_fx","title":"Bearger Fx","description":"Defines visual effect prefabs for Bearger attack animations with self-cleanup logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bearger_fx"},{"id":"game-scripts/prefabs/beargerfur_sack","title":"Beargerfur Sack","description":"Defines the Bearger Fur Sack prefab, a portable storage container that preserves perishable items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beargerfur_sack"},{"id":"game-scripts/prefabs/bee","title":"Bee Prefab","description":"Defines the worker and killer bee prefabs, configuring their AI, combat, and inventory behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bee"},{"id":"game-scripts/prefabs/beefalowool","title":"Beefalowool","description":"Defines the beefalo wool inventory item prefab with burning, stacking, and trading capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefalowool"},{"id":"game-scripts/prefabs/beehive","title":"Beehive","description":"Defines the Beehive prefab entity that spawns bees, handles combat interactions, and drops loot when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beehive"},{"id":"game-scripts/prefabs/beeswax","title":"Beeswax","description":"Defines the beeswax prefab entity, including melting mechanics and inventory stacking behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beeswax"},{"id":"game-scripts/prefabs/bernie_active","title":"Bernie Active","description":"Defines the active state prefab for Bernie, the animated teddy bear companion.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_active"},{"id":"game-scripts/prefabs/bernie_big","title":"Bernie Big","description":"Defines the active Bernie companion prefab with combat, movement, and skill tree integration for Willow\'s character mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bernie_big"},{"id":"game-scripts/prefabs/birds","title":"Birds","description":"Defines and instantiates bird prefabs with shared logic, including loot dropping, mutation behavior, and canary-specific gas poisoning mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birds"},{"id":"game-scripts/prefabs/birdtrap","title":"Birdtrap","description":"Spawnable trap entity that catches birds using bait, with finite uses and visual feedback for trapped bird type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/birdtrap"},{"id":"game-scripts/prefabs/bishop_charge","title":"Bishop Charge","description":"Defines projectile and visual effect prefabs for the Chess Bishop\'s charge attack, including deprecated and updated versions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bishop_charge"},{"id":"game-scripts/prefabs/blueprint_craftingset","title":"Blueprint Craftingset","description":"Creates a temporary entity that, when built, spawns and distributes blueprint prefabs to the builder\'s inventory.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blueprint_craftingset"},{"id":"game-scripts/prefabs/bufferedmapaction","title":"Bufferedmapaction","description":"Classified prefab entity that handles map-based action targeting, synchronizing action requests between client and server via netvars and triggering the player controller\'s map screen.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bufferedmapaction"},{"id":"game-scripts/prefabs/carpentry_blades","title":"Carpentry Blades","description":"Creates a moonglass carpentry blade prefab used as an ingredient in crafting recipes at the carpentry station.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carpentry_blades"},{"id":"game-scripts/prefabs/corpse_gestalt","title":"Corpse Gestalt","description":"Defines the corpse gestalt prefab, a lunar-aligned entity that can be captured and tracked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/corpse_gestalt"},{"id":"game-scripts/prefabs/critters","title":"Critters","description":"Defines prefab factories for creating companion critter entities with hunger, sleep, and follower behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/critters"},{"id":"game-scripts/prefabs/damagenumber","title":"Damagenumber","description":"Renders a damage popup number for the local player when damage is applied, synchronized across the network.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/damagenumber"},{"id":"game-scripts/prefabs/egg","title":"Egg","description":"Prefab file defining three bird egg variants (raw, cooked, rotten) with edible, perishable, fertilizer, and tradable components for inventory and world interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/egg"},{"id":"game-scripts/prefabs/entityproxy","title":"Entityproxy","description":"A lightweight prefab used as a network proxy for replay functionality, containing only essential transform and animation states without persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/entityproxy"},{"id":"game-scripts/prefabs/fx","title":"Fx","description":"Generates and returns a list of Prefab instances for client-side visual and audio effects, supporting dynamic assets, animation, tinting, sound, and custom behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fx"},{"id":"game-scripts/prefabs/gestalt_alterguardian_projectile","title":"Gestalt Alterguardian Projectile","description":"Defines five projectile prefabs used by the Alterguardian boss fight, featuring flight physics, sanity-based transparency, and targeted attack behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gestalt_alterguardian_projectile"},{"id":"game-scripts/prefabs/ghost","title":"Ghost","description":"Prefab file that registers two ghost entity types: the standard player ghost and Wendy\'s grave guard ghost variant, each with combat, aura, and trader components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghost"},{"id":"game-scripts/prefabs/global","title":"Global","description":"Defines the global asset prefab that preloads all core game resources including sounds, images, shaders, animations, and fonts on game initialization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/global"},{"id":"game-scripts/prefabs/globalmapicon","title":"Globalmapicon","description":"Prefab file registering multiple global map icon entities and a factory function for creating tracked entity icons with owner-classified visibility.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/globalmapicon"},{"id":"game-scripts/prefabs/goatmilk","title":"Goatmilk","description":"Spawnable inventory item prefab representing milk from a domesticated beefalo, with edible, perishable, and stackable components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/goatmilk"},{"id":"game-scripts/prefabs/hud","title":"Hud","description":"Defines the HUD prefab responsible for loading user interface assets and dependencies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hud"},{"id":"game-scripts/prefabs/hutch_fishbowl","title":"Hutch Fishbowl","description":"Manages the lifecycle, state, and respawn behavior of a Hutch-following item in the game world, including inventory interaction and persistent state across sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hutch_fishbowl"},{"id":"game-scripts/prefabs/lighterfire_common","title":"Lighterfire Common","description":"Provides a reusable factory function to create fire-based lighting prefabs with networked light range control and sound emission.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lighterfire_common"},{"id":"game-scripts/prefabs/lightningrod","title":"Lightningrod","description":"Spawnable structure entity that attracts lightning strikes, stores electrical charge for up to 3 days, and can be used as a battery component by other devices.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightningrod"},{"id":"game-scripts/prefabs/lunarthrall_plant_gestalt","title":"Lunarthrall Plant Gestalt","description":"Defines the lunarthrall_plant_gestalt prefab entity with AI brain, movement, and gestalt capture mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lunarthrall_plant_gestalt"},{"id":"game-scripts/prefabs/moon_altar_link","title":"Moon Altar Link","description":"Coordinates the activation sequence of the Moon Altar device by linking three altars, clearing surrounding area, and triggering moonstorm events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_altar_link"},{"id":"game-scripts/prefabs/moonrockseed","title":"Moonrockseed","description":"Celestial orb prefab that functions as a portable prototyper with light effects, inventory tracking, and minimap icon integration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonrockseed"},{"id":"game-scripts/prefabs/oceanwhirlbigportal","title":"Oceanwhirlbigportal","description":"Defines the ocean whirlpool migration portal (entry) and the exit pool prefab, handling world migration, visual effects, wave blocking, and loot distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlbigportal"},{"id":"game-scripts/prefabs/oceanwhirlportal","title":"Oceanwhirlportal","description":"Spawnable ocean teleportation structure that detects boats within range and teleports them to a paired exit portal, applying wake effects and watery protection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlportal"},{"id":"game-scripts/prefabs/onemanband","title":"Onemanband","description":"Wearable musical armor prefab that provides dapperness bonuses, summons follower minions, consumes fuel over time, and can be haunted to activate follower effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/onemanband"},{"id":"game-scripts/prefabs/phonograph","title":"Phonograph","description":"Defines the Phonograph prefab, a decorative machine that plays music records and tends nearby farm plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/phonograph"},{"id":"game-scripts/prefabs/pigelite","title":"Pigelite","description":"Creates and configures elite pig warrior prefabs with combat, squad, and sleeper functionality for DST\'s boss encounters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigelite"},{"id":"game-scripts/prefabs/pigtorch_flame","title":"Pigtorch Flame","description":"A visual and audio FX entity representing a pigtorch flame, using layered animation levels and integrated fire effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch_flame"},{"id":"game-scripts/prefablist","title":"Prefablist","description":"A global array containing all registered prefab names available in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefablist"},{"id":"game-scripts/prefabs","title":"Prefabs","description":"Defines core data structures for registering and managing game prefabs and their associated assets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs"},{"id":"game-scripts/prefabutil","title":"Prefabutil","description":"Helper utilities for constructingplacer prefabs and deployable item prefabs in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabutil"},{"id":"game-scripts/prefabs/quagmire_eventstages","title":"Quagmire Eventstages","description":"Defines and creates stage-related prefabs for the Quagmire event by dynamically generating instances from a central event data registry.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_eventstages"},{"id":"game-scripts/prefabs/quagmire_fish","title":"Quagmire Fish","description":"Creates quagmire-region fish prefabs with raw and cooked variants, including animation, inventory physics, and network support for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_fish"},{"id":"game-scripts/prefabs/quagmire_foods","title":"Quagmire Foods","description":"Generates and registers Quagmire mod food prefabs with dynamic asset loading and networked dish customization properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_foods"},{"id":"game-scripts/prefabs/quagmire_traders","title":"Quagmire Traders","description":"Defines two distinct NPC trader prefabs (Merm Trader 1 and 2) for the Quagmire biome with shared behavior and inventory mappings.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_traders"},{"id":"game-scripts/prefabs/sand_spike","title":"Sand Spike","description":"Creates animated ground spikes and blocks that emerge from the sand, deal damage, destroy workable structures, pick plants, and transform into glass when ignited.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sand_spike"},{"id":"game-scripts/prefabs/shadow_battleaxe","title":"Shadow Battleaxe","description":"A levelable shadow weapon prefab with life steal, talking AI, and visual FX systems that progresses through epic creature kills.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_battleaxe"},{"id":"game-scripts/prefabs/shadow_harvester_trail","title":"Shadow Harvester Trail","description":"Visual effect prefab that generates a persistent shadowy trail animation around an entity, managed via client-side particle pooling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_harvester_trail"},{"id":"game-scripts/prefabs/shadow_heart_vein","title":"Shadow Heart Vein","description":"Harvestable shadow biome resource prefab that drops weighted loot based on map topology when chopped down, with visual variation and gem symbol overrides.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_heart_vein"},{"id":"game-scripts/prefabs/shadowheart_infused","title":"Shadowheart Infused","description":"Spawnable item entity that functions as a socketable trinket with sanity aura, drowning detection, and client-side shadow visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowheart_infused"},{"id":"game-scripts/prefabs/spoiledfood","title":"Spoiledfood","description":"Prefab file defining three spoiled food entity variants (spoiled_food, spoiled_fish, spoiled_fish_small) with fertilizer, edible, and rain-disappear mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spoiledfood"},{"id":"game-scripts/prefabs/staff","title":"Staff","description":"Defines multiple magical staff prefabs with unique abilities including fire, ice, teleportation, deconstruction, and light creation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/staff"},{"id":"game-scripts/prefabs/tillweedsalve","title":"Tillweedsalve","description":"Defines two prefabs: the tillweed salve inventory item that heals users, and the tillweed salve buff debuff that applies healing over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tillweedsalve"},{"id":"game-scripts/prefabs/torchfire_common","title":"Torchfire Common","description":"Provides utilities for creating and managing torchlight entities with animated fire effects, networked light range controls, and parented light synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_common"},{"id":"game-scripts/prefabs/tree_rocks","title":"Tree Rocks","description":"Defines the tree_rock prefab family, which functions as a growable tree that transforms into a mineable boulder upon being chopped or burnt.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tree_rocks"},{"id":"game-scripts/prefabs/w_radio","title":"W Radio","description":"Spawnable furniture entity that plays music, tends nearby farm plants, and supports skin customization with modular part variations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/w_radio"},{"id":"game-scripts/prefabs/wagdrone_flying","title":"Wagdrone Flying","description":"Spawnable flying mech entity with targeting marker effects, hackable loot drops, and stategraph-driven animation states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagdrone_flying"},{"id":"game-scripts/prefabs/wagdrone_projectile","title":"Wagdrone Projectile","description":"Defines projectile prefab factories for wagdrone and WX-78 zap drone electrical attacks with area damage and electrocute effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagdrone_projectile"},{"id":"game-scripts/prefabs/warg","title":"Warg","description":"Factory function for creating multiple warg-type prefabs with varying properties, behaviors, and components depending on variant (normal, clay, gingerbread, or mutated).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/warg"},{"id":"game-scripts/prefabs/willow_ember_common","title":"Willow Ember Common","description":"Utility module providing helper functions for Willow\'s ember mechanics and fire burst targeting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/willow_ember_common"},{"id":"game-scripts/prefabs/wormwood_lightflier","title":"Wormwood Lightflier","description":"Prefab definition for Wormwood\'s Lightflier pet entity with formation movement and transformation mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormwood_lightflier"},{"id":"game-scripts/prefabs/wx78_abilitycooldown","title":"Wx78 Abilitycooldown","description":"Invisible networked prefab entity that tracks WX-78 player ability cooldown state via netvars and wall update ticks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_abilitycooldown"},{"id":"game-scripts/prefabs/wx78_backupbody","title":"Wx78 Backupbody","description":"WX-78 character backup body prefab that stores inventory, upgrade modules, and skins for body transfer and resurrection mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_backupbody"},{"id":"game-scripts/prefabs/wx78_classified","title":"Wx78 Classified","description":"Classified data container prefab for WX-78 character that manages upgrade modules, backup bodies, shield state, and energy levels with network replication.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_classified"},{"id":"game-scripts/prefabs/wx78_drone_delivery","title":"Wx78 Drone Delivery","description":"Spawnable delivery drone structure for WX-78 that transports items between map locations, with flying animations, shadow effects, and skill-gated usage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_drone_delivery"},{"id":"game-scripts/prefabs/wx78_drone_scout","title":"Wx78 Drone Scout","description":"WX-78 character skill prefab that creates a scout drone entity for map exploration and area revelation, with delivery mechanics and skin support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_drone_scout"},{"id":"game-scripts/prefabs/wx78_drone_zap","title":"Wx78 Drone Zap","description":"Prefab file defining the WX-78 zap drone entity and its remote controller item, enabling skill-based ranged combat with camera focus control and battery charging.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_drone_zap"},{"id":"game-scripts/prefabs/wx78_foodbrick","title":"Wx78 Foodbrick","description":"WX-78 character-specific food item that transforms between wet and dry states, changing nutritional values and gaining fertilizer properties when wet.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_foodbrick"},{"id":"game-scripts/prefabs/wx78_gestalttrapper","title":"Wx78 Gestalttrapper","description":"Spawnable inventory item prefab for WX-78 that functions as a socketable gestalt trapper component with low socket quality.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_gestalttrapper"},{"id":"game-scripts/prefabs/wx78_heartveinspawner","title":"Wx78 Heartveinspawner","description":"Server-side prefab that periodically spawns shadow_heart_vein entities around WX-78 players using the shadow heart skill mechanic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_heartveinspawner"},{"id":"game-scripts/prefabs/wx78_inventorycontainer","title":"Wx78 Inventorycontainer","description":"WX-78 character-specific inventory container prefab that provides a collapsible storage unit with power state toggling and rummage-style picking behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_inventorycontainer"},{"id":"game-scripts/prefabs/wx78_lightbeam","title":"Wx78 Lightbeam","description":"Prefab entity that creates a dynamic light beam effect attached to WX-78 character, with networked rotation and radius properties, client-side prediction for smooth movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_lightbeam"},{"id":"game-scripts/prefabs/wx78_mimicspawner","title":"Wx78 Mimicspawner","description":"Server-only invisible spawner entity that periodically generates Item Mimic entities for WX-78\'s Mimic Heart skill, with density control and cleanup on removal.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_mimicspawner"},{"id":"game-scripts/prefabs/wx78_moduleremover","title":"Wx78 Moduleremover","description":"Prefab for the WX-78 Module Remover item, allowing removal of installed system modules.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_moduleremover"},{"id":"game-scripts/prefabs/wx78_modules","title":"Wx78 Modules","description":"Prefab factory file that generates WX-78 upgrade module entities with inventory, finite uses, and upgrademodule components for each module definition.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_modules"},{"id":"game-scripts/prefabs/wx78_possessedbody","title":"Wx78 Possessedbody","description":"Prefab for WX-78\'s possessed body form, a gestalt entity that links to a player owner and supports upgrade modules, planar state, and shield mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_possessedbody"},{"id":"game-scripts/prefabs/wx78_scanner","title":"Wx78 Scanner","description":"Defines the WX78 scanner item, deployed scanner entity, succeeded state, and FX prefabs for scanning creatures and unlocking modules.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_scanner"},{"id":"game-scripts/prefabs/wx78_shadow_heart_debuff","title":"Wx78 Shadow Heart Debuff","description":"Server-only prefab entity that applies a timed debuff to WX-78 players via the skills system, automatically expiring after a configured duration or when the target dies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_shadow_heart_debuff"}],"unlisted":false}}')}}]);